251	+export async function DELETE(
252	+  _: Request,
253	+  {
254	+    params,
255	+  }: {
256	+    params: Promise<{id: string; moduleId: string; lessonId: string; assetId: string}>;
257	+  },
258	+) {
259	+  const raw = await params;
260	+  const session = await auth();
261	+
262	+  try {
263	+    if (!session?.user?.id) {
264	+      return NextResponse.json({error: "Unauthorized"}, {status: 401});
265	+    }
266	+
267	+    const parsed = paramsSchema.safeParse(raw);
268	+    if (!parsed.success) {
269	+      return NextResponse.json(
270	+        {error: "Invalid parameters", issues: z.treeifyError(parsed.error)},
271	+        {status: 400},
272	+      );
273	+    }
274	+
275	+    const result = await handleCourseLessonAssetDelete({
276	+      courseId: parsed.data.id,
277	+      moduleId: parsed.data.moduleId,
278	+      lessonId: parsed.data.lessonId,
279	+      assetId: parsed.data.assetId,
280	+      userId: session.user.id,
281	+      isInstructor: Boolean(session.user.roles?.includes("instructor")),
282	+      isAdmin: Boolean(session.user.roles?.includes("admin")),
283	+    });
284	+
285	+    if ("error" in result) {
286	+      return NextResponse.json({error: result.error}, {status: result.status});
287	+    }
288	+
