301	+import {NextResponse} from "next/server";
302	+import {auth} from "@/lib/auth";
303	+import {CourseLessonAssetCreateBodySchema} from "@/lib/courses/curriculum/lessons/commands/assets/course-lesson-asset-create.schema";
304	+import {handleCourseLessonAssetCreate} from "@/lib/courses/curriculum/lessons/handlers/assets/course-lesson-asset-create.handler";
305	+import {handleCourseLessonAssetList} from "@/lib/courses/curriculum/lessons/handlers/assets/course-lesson-asset-list.handler";
306	+import {z} from "zod";
307	+
308	+const paramsSchema = z.object({
309	+  id: z.uuid(),
310	+  moduleId: z.uuid(),
311	+  lessonId: z.uuid(),
312	+});
313	+
314	+export async function GET(
315	+  _: Request,
316	+  {params}: {params: Promise<{id: string; moduleId: string; lessonId: string}>},
317	+) {
318	+  const raw = await params;
319	+  const session = await auth();
320	+
321	+  try {
322	+    if (!session?.user?.id) {
323	+      return NextResponse.json({error: "Unauthorized"}, {status: 401});
324	+    }
325	+
326	+    const parsed = paramsSchema.safeParse(raw);
327	+    if (!parsed.success) {
328	+      return NextResponse.json(
329	+        {error: "Invalid parameters", issues: z.treeifyError(parsed.error)},
330	+        {status: 400},
331	+      );
332	+    }
333	+
334	+    const result = await handleCourseLessonAssetList({
335	+      courseId: parsed.data.id,
336	+      moduleId: parsed.data.moduleId,
337	+      lessonId: parsed.data.lessonId,
338	+      userId: session.user.id,
339	+      isInstructor: Boolean(session.user.roles?.includes("instructor")),
340	+      isAdmin: Boolean(session.user.roles?.includes("admin")),
341	+    });
342	+
343	+    if ("error" in result) {
344	+      return NextResponse.json({error: result.error}, {status: result.status});
345	+    }
346	+
347	+    return NextResponse.json(result.data, {status: result.status});
348	+  } catch (error: unknown) {
349	+    const message = error instanceof Error ? error.message : "Failed to list lesson materials";
350	+    return NextResponse.json({error: message}, {status: 500});
351	+  }
352	+}
353	+
354	+export async function POST(
355	+  request: Request,
356	+  {params}: {params: Promise<{id: string; moduleId: string; lessonId: string}>},
357	+) {
358	+  const raw = await params;
359	+  const session = await auth();
360	+
361	+  try {
362	+    if (!session?.user?.id) {
363	+      return NextResponse.json({error: "Unauthorized"}, {status: 401});
364	+    }
365	+
366	+    const parsedParams = paramsSchema.safeParse(raw);
367	+    if (!parsedParams.success) {
368	+      return NextResponse.json(
369	+        {error: "Invalid parameters", issues: z.treeifyError(parsedParams.error)},
370	+        {status: 400},
371	+      );
372	+    }
373	+
374	+    const body = await request.json();
375	+    const parsedBody = CourseLessonAssetCreateBodySchema.safeParse(body);
376	+    if (!parsedBody.success) {
377	+      return NextResponse.json(
378	+        {error: "Invalid payload", issues: z.treeifyError(parsedBody.error)},
379	+        {status: 400},
380	+      );
381	+    }
382	+
383	+    const result = await handleCourseLessonAssetCreate({
384	+      courseId: parsedParams.data.id,
385	+      moduleId: parsedParams.data.moduleId,
386	+      lessonId: parsedParams.data.lessonId,
387	+      userId: session.user.id,
388	+      isInstructor: Boolean(session.user.roles?.includes("instructor")),
389	+      isAdmin: Boolean(session.user.roles?.includes("admin")),
390	+      data: parsedBody.data,
391	+    });
392	+
393	+    if ("error" in result) {
394	+      return NextResponse.json({error: result.error}, {status: result.status});
395	+    }
396	+
397	+    return NextResponse.json(result.data, {status: result.status});
398	+  } catch (error: unknown) {
399	+    const message = error instanceof Error ? error.message : "Failed to create lesson material";
400	+    return NextResponse.json({error: message}, {status: 500});
401	+  }
402	+}
