@@ -0,0 +1,102 @@
+import {NextResponse} from "next/server";
+import {auth} from "@/lib/auth";
+import {CourseLessonAssetCreateBodySchema} from "@/lib/courses/curriculum/lessons/commands/assets/course-lesson-asset-create.schema";
+import {handleCourseLessonAssetCreate} from "@/lib/courses/curriculum/lessons/handlers/assets/course-lesson-asset-create.handler";
+import {handleCourseLessonAssetList} from "@/lib/courses/curriculum/lessons/handlers/assets/course-lesson-asset-list.handler";
+import {z} from "zod";
+
+const paramsSchema = z.object({
+  id: z.uuid(),
+  moduleId: z.uuid(),
+  lessonId: z.uuid(),
+});
+
+export async function GET(
+  _: Request,
+  {params}: {params: Promise<{id: string; moduleId: string; lessonId: string}>},
+) {
+  const raw = await params;
+  const session = await auth();
+
+  try {
+    if (!session?.user?.id) {
+      return NextResponse.json({error: "Unauthorized"}, {status: 401});
+    }
+
+    const parsed = paramsSchema.safeParse(raw);
+    if (!parsed.success) {
+      return NextResponse.json(
+        {error: "Invalid parameters", issues: z.treeifyError(parsed.error)},
+        {status: 400},
+      );
+    }
+
+    const result = await handleCourseLessonAssetList({
+      courseId: parsed.data.id,
+      moduleId: parsed.data.moduleId,
+      lessonId: parsed.data.lessonId,
+      userId: session.user.id,
+      isInstructor: Boolean(session.user.roles?.includes("instructor")),
+      isAdmin: Boolean(session.user.roles?.includes("admin")),
+    });
+
+    if ("error" in result) {
+      return NextResponse.json({error: result.error}, {status: result.status});
+    }
+
+    return NextResponse.json(result.data, {status: result.status});
+  } catch (error: unknown) {
+    const message = error instanceof Error ? error.message : "Failed to list lesson materials";
+    return NextResponse.json({error: message}, {status: 500});
+  }
+}
+
+export async function POST(
+  request: Request,
+  {params}: {params: Promise<{id: string; moduleId: string; lessonId: string}>},
+) {
+  const raw = await params;
+  const session = await auth();
+
+  try {
+    if (!session?.user?.id) {
+      return NextResponse.json({error: "Unauthorized"}, {status: 401});
+    }
+
+    const parsedParams = paramsSchema.safeParse(raw);
+    if (!parsedParams.success) {
+      return NextResponse.json(
+        {error: "Invalid parameters", issues: z.treeifyError(parsedParams.error)},
+        {status: 400},
+      );
+    }
+
+    const body = await request.json();
+    const parsedBody = CourseLessonAssetCreateBodySchema.safeParse(body);
+    if (!parsedBody.success) {
+      return NextResponse.json(
+        {error: "Invalid payload", issues: z.treeifyError(parsedBody.error)},
+        {status: 400},
+      );
+    }
+
+    const result = await handleCourseLessonAssetCreate({
+      courseId: parsedParams.data.id,
+      moduleId: parsedParams.data.moduleId,
+      lessonId: parsedParams.data.lessonId,
+      userId: session.user.id,
+      isInstructor: Boolean(session.user.roles?.includes("instructor")),
+      isAdmin: Boolean(session.user.roles?.includes("admin")),
+      data: parsedBody.data,
+    });
+
+    if ("error" in result) {
+      return NextResponse.json({error: result.error}, {status: result.status});
+    }
+
+    return NextResponse.json(result.data, {status: result.status});
+  } catch (error: unknown) {
+    const message = error instanceof Error ? error.message : "Failed to create lesson material";
+    return NextResponse.json({error: message}, {status: 500});
+  }
+}
