480	+export async function handleCourseLessonAssetCreate(command: {
481	+  courseId: string;
482	+  moduleId: string;
483	+  lessonId: string;
484	+  userId: string;
485	+  isInstructor: boolean;
486	+  isAdmin?: boolean;
487	+  data: CourseLessonAssetCreateBody;
488	+}) {
489	+  const {courseId, moduleId, lessonId, userId, isInstructor, isAdmin = false} = command;
490	+
491	+  if (!isInstructor && !isAdmin) {
492	+    return {error: "Only instructors can add lesson materials", status: 403 as const};
493	+  }
494	+
495	+  const access = await assertCourseWriteAccess({courseId, userId, isAdmin});
496	+  if (!access.ok) {
497	+    return {error: access.error, status: access.status};
498	+  }
499	+
500	+  const contentEditable = await assertCourseContentEditable(courseId, {isAdmin});
501	+  if (!contentEditable.ok) {
502	+    return {error: contentEditable.error, status: contentEditable.status};
503	+  }
504	+
505	+  const lesson = await prisma.courseLesson.findFirst({
506	+    where: {id: lessonId, moduleId, module: {courseId}},
507	+    select: {id: true},
508	+  });
509	+
510	+  if (!lesson) {
511	+    return {error: "Lesson not found", status: 404 as const};
512	+  }
513	+
514	+  const lastAsset = await prisma.courseLessonAsset.findFirst({
515	+    where: {lessonId, role: "resource"},
516	+    orderBy: {position: "desc"},
517	+    select: {position: true},
518	+  });
519	+  const nextPosition = (lastAsset?.position ?? -1) + 1;
520	+
521	+  const created = await prisma.courseLessonAsset.create({
522	+    data: {
523	+      lesson: {connect: {id: lessonId}},
524	+      role: "resource",
525	+      position: nextPosition,
526	+      title: command.data.title ?? null,
527	+      kind: command.data.kind,
528	+      isDownloadable: command.data.isDownloadable ?? false,
529	+      ...(command.data.attachmentId
530	+        ? {attachment: {connect: {id: command.data.attachmentId}}}
531	+        : {url: command.data.url}),
532	+    },
533	+    include: {attachment: {include: {file: true}}},
534	+  });
535	+
536	+  return {
537	+    data: synthesizeLessonResourceDTO(created, mapLessonAssetToDTO(created)),
538	+    status: 201 as const,
539	+  };
540	+}
