+import {prisma} from "@/lib/prisma";
+import {mapLessonAssetToDTO} from "@/lib/courses/assets/course-asset.helpers";
+import {assertCourseWriteAccess} from "@/lib/courses/catalog/guards/course-access.guard";
+import {assertCourseContentEditable} from "@/lib/courses/catalog/guards/course-edit.guard";
+import type {CourseLessonAssetCreateBody} from "@/lib/courses/curriculum/lessons/commands/assets/course-lesson-asset-create.schema";
+import {synthesizeLessonResourceDTO} from "@/lib/courses/curriculum/lessons/helpers/synthesize-lesson-resource-dto";
+
+export async function handleCourseLessonAssetCreate(command: {
+  courseId: string;
+  moduleId: string;
+  lessonId: string;
+  userId: string;
+  isInstructor: boolean;
+  isAdmin?: boolean;
+  data: CourseLessonAssetCreateBody;
+}) {
+  const {courseId, moduleId, lessonId, userId, isInstructor, isAdmin = false} = command;
+
+  if (!isInstructor && !isAdmin) {
+    return {error: "Only instructors can add lesson materials", status: 403 as const};
+  }
+
+  const access = await assertCourseWriteAccess({courseId, userId, isAdmin});
+  if (!access.ok) {
+    return {error: access.error, status: access.status};
+  }
+
+  const contentEditable = await assertCourseContentEditable(courseId, {isAdmin});
+  if (!contentEditable.ok) {
+    return {error: contentEditable.error, status: contentEditable.status};
+  }
+
+  const lesson = await prisma.courseLesson.findFirst({
+    where: {id: lessonId, moduleId, module: {courseId}},
+    select: {id: true},
+  });
+
+  if (!lesson) {
+    return {error: "Lesson not found", status: 404 as const};
+  }
+
+  const lastAsset = await prisma.courseLessonAsset.findFirst({
+    where: {lessonId, role: "resource"},
+    orderBy: {position: "desc"},
+    select: {position: true},
+  });
+  const nextPosition = (lastAsset?.position ?? -1) + 1;
+
+  const created = await prisma.courseLessonAsset.create({
+    data: {
+      lesson: {connect: {id: lessonId}},
+      role: "resource",
+      position: nextPosition,
+      title: command.data.title ?? null,
+      kind: command.data.kind,
+      isDownloadable: command.data.isDownloadable ?? false,
+      ...(command.data.attachmentId
+        ? {attachment: {connect: {id: command.data.attachmentId}}}
+        : {url: command.data.url}),
+    },
+    include: {attachment: {include: {file: true}}},
+  });
+
+  return {
+    data: synthesizeLessonResourceDTO(created, mapLessonAssetToDTO(created)),
+    status: 201 as const,
+  };
+}
