+import {prisma} from "@/lib/prisma";
+import {assertCourseWriteAccess} from "@/lib/courses/catalog/guards/course-access.guard";
+import {assertCourseContentEditable} from "@/lib/courses/catalog/guards/course-edit.guard";
+
+export async function handleCourseLessonAssetDelete(command: {
+  courseId: string;
+  moduleId: string;
+  lessonId: string;
+  assetId: string;
+  userId: string;
+  isInstructor: boolean;
+  isAdmin?: boolean;
+}) {
+  const {courseId, moduleId, lessonId, assetId, userId, isInstructor, isAdmin = false} = command;
+
+  if (!isInstructor && !isAdmin) {
+    return {error: "Only instructors can remove lesson materials", status: 403 as const};
+  }
+
+  const access = await assertCourseWriteAccess({courseId, userId, isAdmin});
+  if (!access.ok) {
+    return {error: access.error, status: access.status};
+  }
+
+  const contentEditable = await assertCourseContentEditable(courseId, {isAdmin});
+  if (!contentEditable.ok) {
+    return {error: contentEditable.error, status: contentEditable.status};
+  }
+
+  const lessonAsset = await prisma.courseLessonAsset.findFirst({
+    where: {
+      id: assetId,
+      lessonId,
+      lesson: {moduleId, module: {courseId}},
+    },
+    select: {id: true},
+  });
+
+  if (!lessonAsset) {
+    return {error: "Lesson material not found", status: 404 as const};
+  }
+
+  await prisma.courseLessonAsset.delete({where: {id: lessonAsset.id}});
+
+  return {data: {ok: true}, status: 200 as const};
+}
