+import type {LessonResourceDTO} from "@/lib/courses/curriculum/lessons/dto/lesson.dto";
+import type {LessonResourceType} from "@/lib/courses/curriculum/lessons/types";
+import type {LessonAssetDTO} from "@/lib/courses/assets/course-asset.dto";
+
+type LessonAssetRow = {
+  id: string;
+  lessonId: string;
+  title: string | null;
+  kind: string;
+  position: number;
+  isDownloadable: boolean;
+  createdAt: Date;
+  updatedAt: Date;
+  attachment?: {
+    filename: string | null;
+    file: {mimeType: string; size: number};
+  } | null;
+};
+
+/**
+ * Adapts a CourseLessonAsset row (role='resource') into the legacy
+ * LessonResourceDTO shape that the curriculum mapper has been synthesizing
+ * for UI back-compat. Extracted so the create/list handlers and the lesson
+ * mapper share one source of truth.
+ */
+export function synthesizeLessonResourceDTO(
+  asset: LessonAssetRow,
+  mapped: Pick<LessonAssetDTO, "url">,
+): LessonResourceDTO {
+  return {
+    id: asset.id,
+    lessonId: asset.lessonId,
+    title: asset.title ?? asset.attachment?.filename ?? mapped.url.split("/").pop() ?? "Resource",
+    type: (asset.kind === "link" ? "link" : "file") as LessonResourceType,
+    url: mapped.url,
+    position: asset.position,
+    isDownloadable: asset.isDownloadable,
+    mimeType: asset.attachment?.file.mimeType ?? null,
+    size: asset.attachment?.file.size ?? null,
+    createdAt: asset.createdAt.toISOString(),
+    updatedAt: asset.updatedAt.toISOString(),
+  };
+}
