+/**
+ * Builds the public CDN URL for an uploaded file by joining R2_PUBLIC_URL
+ * with the file's storage key. Mirrors uploadPublicAsset.command.ts, which
+ * returns the same shape after a successful PUT.
+ *
+ * Use this when you have the `File.key` and want the direct CDN URL that
+ * the browser can fetch without going through the app's API. For
+ * authorization-gated reads (signed URLs, per-request ACL), use
+ * buildAttachmentContentUrl instead.
+ */
+export function buildAttachmentCdnUrl(file: {key: string}): string {
+  const base = process.env.R2_PUBLIC_URL;
+  if (!base) {
+    throw new Error("R2_PUBLIC_URL is not set");
+  }
+  return `${base}/${file.key}`;
+}
