24	 * - The previous prefix-match (`image/*` or `video/*`) would have served
25	 *   SVG inline, defeating the XSS mitigation.
26	 *
27	 * Every MIME here must also be in the upload route's
28	 * `ALLOWED_IMAGE_TYPES` / `ALLOWED_VIDEO_TYPES`.
29	 */
30	const INLINE_RENDERABLE_MIME_TYPES = new Set<string>([
31	  "image/jpeg",
32	  "image/jpg",
33	  "image/png",
34	  "image/gif",
35	  "image/webp",
36	  "video/mp4",
37	  "video/webm",
38	  "video/ogg",
39	  "video/quicktime",
40	]);
