59	  const fallback = sanitizeAsciiFilename(displayFilename);
60	  const needsExtended = /[^\x20-\x7e]/.test(displayFilename) || fallback !== displayFilename;
61	
62	  if (!needsExtended) {
63	    return `attachment; filename="${fallback}"`;
64	  }
65	
66	  const encoded = encodeURIComponent(displayFilename).replace(
67	    /['()*]/g,
68	    (c) => `%${c.charCodeAt(0).toString(16).toUpperCase()}`,
69	  );
70	  return `attachment; filename="${fallback}"; filename*=UTF-8''${encoded}`;
71	}
