73	export async function uploadPublicAsset({
74	  key,
75	  buffer,
76	  contentType,
77	  displayFilename,
78	}: UploadPublicAssetInput) {
79	  const bucket = process.env.R2_BUCKET_STATIC;
80	  const publicUrl = process.env.R2_PUBLIC_URL;
81	
82	  if (!bucket) {
83	    throw new Error("R2_BUCKET_STATIC is not set");
84	  }
85	  if (!publicUrl) {
86	    throw new Error("R2_PUBLIC_URL is not set");
87	  }
88	
89	  const fallbackName = key.split("/").pop() || "file";
90	  const downloadName = displayFilename?.trim() || fallbackName;
91	
92	  const putCommand: ConstructorParameters<typeof PutObjectCommand>[0] = {
93	    Bucket: bucket,
94	    Key: key,
95	    Body: buffer,
96	    ContentType: contentType,
97	    CacheControl: "public, max-age=31536000, immutable",
98	  };
99	
100	  if (!isInlineRenderableMime(contentType)) {
101	    putCommand.ContentDisposition = buildContentDispositionHeader(downloadName);
102	  }
103	
