35	export function mapLessonToDTO(lesson: LessonWithRelations): LessonDTO {
36	  const assets = lesson.assets?.map(mapLessonAssetToDTO);
37	  const primaryVideo = lesson.assets
38	    ?.filter((asset) => asset.role === "primary_video")
39	    .sort((a, b) => a.position - b.position)[0];
40	
41	  // Synthesize the legacy `resources` array from role='resource' assets so
42	  // existing UI consumers keep working. New code should read `assets` directly.
43	  // Same helper is used by the lesson-assets create/list handlers, so the
44	  // shape returned by GET .../lesson-assets matches what's embedded here.
45	  const resources: LessonResourceDTO[] | undefined = lesson.assets
46	    ?.filter((asset) => asset.role === "resource")
47	    .sort((a, b) => a.position - b.position)
48	    .map((asset) => synthesizeLessonResourceDTO(asset, mapLessonAssetToDTO(asset)));
49	
50	  const prerequisites = lesson.prerequisites?.map((item) => item.prerequisiteLessonId);
51	
52	  return {
53	    id: lesson.id,
54	    moduleId: lesson.moduleId,
55	    title: lesson.title,
56	    description: lesson.description ?? null,
57	    content: lesson.content ?? null,
58	    videoUrl: primaryVideo ? mapLessonAssetToDTO(primaryVideo).url : (lesson.videoUrl ?? null),
59	    duration: lesson.duration ?? null,
60	    position: lesson.position,
61	    isFree: lesson.isFree,
62	    type: lesson.type as LessonType,
63	    ...(assets ? {assets} : {}),
64	    ...(resources && resources.length > 0 ? {resources} : {}),
65	    ...(prerequisites ? {prerequisites} : {}),
66	    createdAt: lesson.createdAt.toISOString(),
67	    updatedAt: lesson.updatedAt.toISOString(),
68	  };
69	}
